    this->w = w;

    this->d = d;

  }



  void cut(int s) {

    int t = s%(w+d);

    int a, b;

    if(t<w) {

      // vertical

      if(t<w-t) {

	a = t;

	b = w-t;

      } else {

	a = w-t;

	b = t;

      }

      pieces.push_back(Cake(a, d));

      pieces.push_back(Cake(b, d));

