    else {

      // horizontal

      t -= w;

      if(t<d-t) {

	a = t;

	b = d-t;

      } else {

	a = d-t;

	b = t;

      }

      pieces.push_back(Cake(w, a));

      pieces.push_back(Cake(w, b));

    }

